// Call Groq API to generate personalized email
const config = $('Merge User Config with Resume Data').item.json;
const job = items[0].json;

const prompt = `You are a professional email writer. Generate a personalized cold email to a recruiter.

**Job Details:**
- Title: ${job['Job Title'] || job.jobTitle}
- Company: ${job.Company || job.company}
- Recruiter: ${job['Recruiter Name'] || job.recruiterName || 'Hiring Manager'}
- Location: ${job.Location || job.location}
- Apply URL: ${job['Apply URL'] || job.applyUrl}
- Job Description: ${(job.Description || job.description || '').substring(0, 800)}
- Requirements: ${(job.Requirements || job.requirements || '').substring(0, 400)}

**Candidate Profile:**
- Name: ${config.name}
- Current Role: ${config.currentRole}
- Experience: ${config.experience}
- Skills: ${(config.skills || []).join(', ')}
- Location: ${config.location}

**Resume Insights:**
- Key Projects: ${((config.resumeData || {}).projects || []).slice(0, 3).map(p => p.name + ' (' + (p.technologies || []).join(', ') + ')').join('; ')}
- Recent Experience: ${((config.resumeData || {}).experience || []).slice(0, 2).map(e => e.role + ' at ' + e.company).join('; ')}
- Achievements: ${((config.resumeData || {}).achievements || []).slice(0, 2).join('; ')}

**Requirements:**
1. Professional, concise (150-200 words)
2. Reference SPECIFIC details from the job description
3. Mention 2-3 specific projects from resume that align with job requirements
4. Highlight matching technical skills
5. Include a clear call-to-action
6. End with "Best regards, ${config.name}"
7. DO NOT be generic - every sentence must reference something specific

**Format:**
Subject: [Compelling subject referencing specific role and one key qualification]

[Email body]

Provide ONLY the subject line and email body. No additional commentary.`;

const response = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://api.groq.com/openai/v1/chat/completions',
  headers: {
    'Authorization': 'Bearer ' + (config.groqApiKey || $env.GROQ_API_KEY || ''),
    'Content-Type': 'application/json'
  },
  body: JSON.stringify({
    model: 'llama-3.3-70b-versatile',
    messages: [{ role: 'user', content: prompt }],
    temperature: 0.7
  }),
  json: true,
  timeout: 60000
});

const aiText = response.choices[0].message.content;

return [{
  json: {
    ...job,
    response: aiText,
    text: aiText
  }
}];

// Parse Groq email response
const jobData = items[0].json;
const groqResponse = $node["Groq AI: Generate Personalized Email"].json.response || $node["Groq AI: Generate Personalized Email"].json.text || '';

let subject = `Application for ${jobData['Job Title'] || jobData.jobTitle} at ${jobData.Company || jobData.company}`;
let body = groqResponse;

// Try to extract subject line
const subjectMatch = groqResponse.match(/Subject:\s*(.+?)\n/i);
if (subjectMatch) {
  subject = subjectMatch[1].trim();
  body = groqResponse.replace(/Subject:\s*.+?\n/i, '').trim();
}

const config = $('Merge User Config with Resume Data').item.json;

// Add signature if not present
if (!body.includes(config.name)) {
  body += `\n\nBest regards,\n${config.name}`;
}

// Add profile links
body += `\n\nPortfolio: ${config.portfolioUrl}`;
body += `\nLinkedIn: ${config.linkedinUrl}`;
body += `\nGitHub: ${config.githubUrl}`;
body += `\nResume: ${config.resumeUrl}`;

return [{
  json: {
    ...jobData,
    emailSubject: subject,
    emailBody: body,
    sentDate: new Date().toISOString().split('T')[0]
  }
}];

// Update status and add metadata
const applicationId = `EMAIL-${Date.now()}-${Math.random().toString(36).substr(2, 6)}`;

return [{
  json: {
    ...items[0].json,
    Status: 'Email Sent',
    status: 'Email Sent',
    'Application ID': applicationId,
    applicationId: applicationId,
    'Email Sent Date': new Date().toISOString().split('T')[0],
    emailSentDate: new Date().toISOString().split('T')[0],
    'Last Updated': new Date().toISOString().split('T')[0],
    lastUpdated: new Date().toISOString().split('T')[0]
  }
}];

// Aggregate sending summary with 4-account breakdown
const jobs = items.map(item => item.json);
const total = jobs.length;

// Count emails sent per account
const accountBreakdown = {
  account1: 0,
  account2: 0,
  account3: 0,
  account4: 0
};

jobs.forEach(j => {
  const account = j.accountUsed;
  if (account && accountBreakdown.hasOwnProperty(account)) {
    accountBreakdown[account]++;
  }
});

const sentList = jobs.map(j => 
  `• **${j['Job Title'] || j.jobTitle}** at **${j.Company || j.company}** → ${j['Recruiter Email'] || j.recruiterEmail} [${j.accountUsed || 'unknown'}]`
);

return [{
  json: {
    total,
    sentList: sentList.join('\n'),
    date: new Date().toISOString().split('T')[0],
    account1Count: accountBreakdown.account1,
    account2Count: accountBreakdown.account2,
    account3Count: accountBreakdown.account3,
    account4Count: accountBreakdown.account4
  }
}];

// Extract message and user info
const message = items[0].json.message || {};

const userId = message.from?.id?.toString() || 'unknown';
const username = message.from?.username || message.from?.first_name || 'User';
const chatId = message.chat?.id;
const text = message.text || '';

return [{
  json: {
    userId,
    username,
    chatId,
    text,
    timestamp: new Date().toISOString()
  }
}];

// Quick command handler
const text = items[0].json.text.toLowerCase();
const config = $('User Config (Master Profile)').item.json;

let quickResponse = '';
let isQuickCommand = false;
let needsStateReport = false;

if (text === '/start' || text === '/help') {
  isQuickCommand = true;
  quickResponse = `**Job Hunt Assistant**

Welcome ${config.name}! 

**Commands:**
• /stats - View your application stats
• /status - View all account states in real-time
• /resume - View your resume
• /help - Show this help message

Ask me anything about your job search!`;
} else if (text === '/resume') {
  isQuickCommand = true;
  quickResponse = `**Your Resume:**
${config.resumeUrl}

**Profile:**
• ${config.currentRole}
• ${config.experience}
• Skills: ${config.skills.join(', ')}
• Location: ${config.location}

**Links:**
LinkedIn: ${config.linkedinUrl}
GitHub: ${config.githubUrl}
Portfolio: ${config.portfolioUrl}`;
} else if (text === '/status') {
  needsStateReport = true;
  isQuickCommand = false; // Will need state report
  quickResponse = '';
} else if (text === '/stats') {
  isQuickCommand = false; // Will need sheet query
  quickResponse = '';
}

return [{
  json: {
    ...items[0].json,
    quickResponse,
    isQuickCommand,
    needsStateReport
  }
}];

// Build dynamic system prompt for Groq
const config = $('User Config (Master Profile)').item.json;
const userMessage = $('Extract Telegram Message').item.json;

const systemPrompt = `You are ${config.name}'s personal job hunt assistant.

**User Profile:**
- Current Role: ${config.currentRole}
- Target Role: ${config.targetRole}
- Experience: ${config.experience}
- Skills: ${config.skills.join(', ')}
- Location: ${config.location}
- Work Preference: ${config.workMode.join(' or ')}
- Minimum Salary: $${config.minSalary}

**Your Capabilities:**
1. Query job tracker (see applications, stats, pending jobs)
2. Provide resume information
3. Answer job search questions
4. Give career advice

**Guidelines:**
- Be concise and action-oriented
- Suggest next steps
- Use bullet points for lists
- Keep responses under 300 words
- Be encouraging and supportive

User message: ${userMessage.text}`;

return [{
  json: {
    ...items[0].json,
    systemPrompt,
    userMessage: userMessage.text
  }
}];

// Call Groq API for Telegram AI assistant
const input = items[0].json;
const systemPrompt = input.systemPrompt || 'You are a helpful job search assistant.';
const userMessage = input.userMessage || input.text || '';

const config = $('User Config (Master Profile)').item.json;

const response = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://api.groq.com/openai/v1/chat/completions',
  headers: {
    'Authorization': 'Bearer ' + (config.groqApiKey || $env.GROQ_API_KEY || ''),
    'Content-Type': 'application/json'
  },
  body: JSON.stringify({
    model: 'llama-3.3-70b-versatile',
    messages: [
      { role: 'system', content: systemPrompt },
      { role: 'user', content: userMessage }
    ],
    temperature: 0.7
  }),
  json: true,
  timeout: 60000
});

const aiText = response.choices[0].message.content;

return [{
  json: {
    ...input,
    response: aiText,
    text: aiText
  }
}];

// Parse agent response and extract actions
const response = items[0].json.response || items[0].json.text || 'Sorry, I could not process your request.';
const userMessage = $('Extract Telegram Message').item.json.text.toLowerCase();

// Detect action intents
const needsSheetQuery = userMessage.includes('stats') || userMessage.includes('status') || userMessage.includes('how many') || userMessage.includes('count');

return [{
  json: {
    ...items[0].json,
    response,
    needsSheetQuery
  }
}];

// Aggregate sheet stats
const jobs = items.map(item => item.json);

const total = jobs.length;
const statusCounts = jobs.reduce((acc, j) => {
  const status = j.Status || j.status || 'Unknown';
  acc[status] = (acc[status] || 0) + 1;
  return acc;
}, {});

const priorityCounts = jobs.reduce((acc, j) => {
  const priority = j.Priority || j.priority || 'unknown';
  acc[priority] = (acc[priority] || 0) + 1;
  return acc;
}, {});

const stats = `**Your Job Tracker Stats:**
• Total jobs: ${total}

**Status Breakdown:**
` + Object.entries(statusCounts).map(([status, count]) => 
  `• ${status}: ${count}`
).join('\n') + `

**Priority Breakdown:**
` + Object.entries(priorityCounts).map(([priority, count]) => 
  `• ${priority}: ${count}`
).join('\n');

return [{
  json: {
    ...items[0].json,
    stats
  }
}];

