// Call Groq API to parse resume
const resumeText = $('Download Resume').item.json.data || '';
const config = $('User Config (Master Profile)').item.json;

const prompt = `You are a resume parser. Extract structured information from this resume text.

**Resume Content:**
${resumeText}

**Extract the following in JSON format ONLY:**
{
  "skills": ["skill1", "skill2", ...],
  "experience": [
    {
      "role": "Job Title",
      "company": "Company Name",
      "duration": "2020-2023",
      "responsibilities": "Key achievements and responsibilities"
    }
  ],
  "projects": [
    {
      "name": "Project Name",
      "description": "Brief description",
      "technologies": ["tech1", "tech2"]
    }
  ],
  "achievements": ["achievement1", "achievement2", ...],
  "education": [
    {
      "degree": "Degree Name",
      "institution": "University Name",
      "year": "2019"
    }
  ]
}

Provide ONLY valid JSON. No additional text or explanation.`;

const response = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://api.groq.com/openai/v1/chat/completions',
  headers: {
    'Authorization': 'Bearer ' + (config.groqApiKey || $env.GROQ_API_KEY || ''),
    'Content-Type': 'application/json'
  },
  body: JSON.stringify({
    model: 'llama-3.3-70b-versatile',
    messages: [{ role: 'user', content: prompt }],
    temperature: 0.1
  }),
  json: true,
  timeout: 60000
});

const aiText = response.choices[0].message.content;

return [{
  json: {
    ...items[0].json,
    response: aiText,
    text: aiText
  }
}];

// Parse and validate Groq resume response
const config = $('User Config (Master Profile)').item.json;
const groqResponse = $node["Parse Resume with Groq AI"].json.response || $node["Parse Resume with Groq AI"].json.text || '';

let resumeData = {
  skills: config.skills || [],
  experience: [],
  projects: [],
  achievements: [],
  education: [],
  parsed: false
};

try {
  // Extract JSON from response
  const jsonMatch = groqResponse.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    const parsed = JSON.parse(jsonMatch[0]);

    // Validate and use parsed data
    if (parsed.skills && Array.isArray(parsed.skills) && parsed.skills.length > 0) {
      resumeData.skills = parsed.skills;
      resumeData.parsed = true;
    }

    if (parsed.experience && Array.isArray(parsed.experience)) {
      resumeData.experience = parsed.experience;
    }

    if (parsed.projects && Array.isArray(parsed.projects)) {
      resumeData.projects = parsed.projects;
    }

    if (parsed.achievements && Array.isArray(parsed.achievements)) {
      resumeData.achievements = parsed.achievements;
    }

    if (parsed.education && Array.isArray(parsed.education)) {
      resumeData.education = parsed.education;
    }
  }
} catch (error) {
  console.error('Resume parsing failed, using User Config fallback:', error.message);
}

return [{
  json: {
    resumeData,
    config
  }
}];

// Use User Config when resume download/parsing fails
