// Select active Google Sheets credential based on account state
const staticData = this.getWorkflowStaticData('global');
const config = $('User Config (Master Profile)').item.json;

// Initialize if not exists
if (!staticData.sheetsAccountState) {
  staticData.sheetsAccountState = {
    account1: { email: 'raviintouch2@gmail.com', dailyWrites: 0, credentialId: '', lastError: null },
    account2: { email: 'ravitejavallakatla7@gmail.com', dailyWrites: 0, credentialId: '', lastError: null },
    account3: { email: 'ravitejav081@gmail.com', dailyWrites: 0, credentialId: '', lastError: null },
    account4: { email: 'ravitejav0801@gmail.com', dailyWrites: 0, credentialId: '', lastError: null },
    currentActive: 'account1',
    lastResetDate: null
  };
}

const state = staticData.sheetsAccountState;
const maxWrites = config.maxSheetsWritesPerAccount || 300;

// Find first available account
const accounts = ['account1', 'account2', 'account3', 'account4'];
let accountToUse = state.currentActive;

for (const acc of accounts) {
  if (state[acc].dailyWrites < maxWrites && !state[acc].lastError) {
    accountToUse = acc;
    break;
  }
}

// Map to credential IDs
const credentialMap = {
  account1: config.sheetsAccount1CredentialId,
  account2: config.sheetsAccount2CredentialId,
  account3: config.sheetsAccount3CredentialId,
  account4: config.sheetsAccount4CredentialId
};

return [{
  json: {
    ...items[0].json,
    sheetsAccountToUse: accountToUse,
    sheetsCredentialId: credentialMap[accountToUse],
    sheetsAccountEmail: state[accountToUse].email
  }
}];

// Handle Google Sheets API errors and trigger account switch
// (Centralised state version - reads multiAccountState.sheets)
const staticData = this.getWorkflowStaticData('global');
const item = items[0].json;

// Pass through if state not initialised yet
if (!staticData.multiAccountState || !staticData.multiAccountState.sheets) {
  return [{ json: { ...item, errorHandled: false, reason: 'state not initialised' } }];
}

const state = staticData.multiAccountState.sheets;
let switched = false;
let switchReason = '';

if (item.error) {
  const errorCode = item.error.httpCode || item.error.code;
  const errorMessage = item.error.message || '';

  // Detect quota / rate-limit errors
  if (errorCode === 429 || errorCode === 403 ||
      errorMessage.includes('quota') || errorMessage.includes('rate limit')) {
    const currentAccount = state.currentActive;
    state[currentAccount].lastError = { code: errorCode, message: errorMessage, time: new Date().toISOString() };

    // Find next viable account
    const accounts = ['account1', 'account2', 'account3', 'account4'];
    const currentIndex = accounts.indexOf(currentAccount);
    const config = $('User Config (Master Profile)').item.json;
    const maxWrites = config.maxSheetsWritesPerAccount || 300;

    for (let i = 1; i <= 4; i++) {
      const next = accounts[(currentIndex + i) % 4];
      if (state[next].dailyWrites < maxWrites && !state[next].lastError) {
        state.currentActive = next;
        switched = true;
        switchReason = `Error ${errorCode}: ${errorMessage}`;
        console.log(`Sheets account switched from ${currentAccount} to ${next} due to error`);
        break;
      }
    }
  }
}

return [{
  json: {
    ...item,
    errorHandled: true,
    sheetsAccountSwitched: switched,
    sheetsSwitchReason: switchReason,
    sheetsAccount: state.currentActive,
    sheetsNeedsSwitch: switched
  }
}];

// Update Sheets write counter - Uses centralized state
const staticData = this.getWorkflowStaticData('global');
const state = staticData.multiAccountState.sheets;
const config = $('User Config (Master Profile)').item.json;
const maxWrites = config.maxSheetsWritesPerAccount || 300;

const currentAccount = state.currentActive;

// Increment write count
state[currentAccount].dailyWrites++;

console.log(`Sheets write recorded: ${state[currentAccount].email} - ${state[currentAccount].dailyWrites}/${maxWrites}`);

// Check if we need to switch accounts (reached daily limit)
let needsSwitch = false;
let switchReason = '';

if (state[currentAccount].dailyWrites >= maxWrites) {
  // Find next available account
  const accounts = ['account1', 'account2', 'account3', 'account4'];
  const currentIndex = accounts.indexOf(currentAccount);

  for (let i = 1; i <= 4; i++) {
    const nextIndex = (currentIndex + i) % 4;
    const nextAccount = accounts[nextIndex];

    if (state[nextAccount].dailyWrites < maxWrites && !state[nextAccount].lastError) {
      state.currentActive = nextAccount;
      needsSwitch = true;
      switchReason = `Daily write limit reached (${state[currentAccount].dailyWrites}/${maxWrites})`;
      console.log(`Sheets account switched from ${currentAccount} to ${nextAccount}`);
      break;
    }
  }
}

return [{
  json: {
    ...items[0].json,
    sheetsWriteRecorded: true,
    sheetsAccount: currentAccount,
    sheetsWriteCount: state[currentAccount].dailyWrites,
    sheetsNeedsSwitch: needsSwitch,
    sheetsSwitchReason: switchReason,
    account1Writes: state.account1.dailyWrites,
    account2Writes: state.account2.dailyWrites,
    account3Writes: state.account3.dailyWrites,
    account4Writes: state.account4.dailyWrites
  }
}];

// Groq API Key state - Now reads from centralized Multi-Account State Manager
const staticData = this.getWorkflowStaticData('global');

// Ensure centralized state exists
if (!staticData.multiAccountState || !staticData.multiAccountState.groq) {
  if (!staticData.multiAccountState) {
    staticData.multiAccountState = {
      gmail: { account1: {}, account2: {}, account3: {}, account4: {}, currentActive: 'account1' },
