    totalSwitches: state.switchHistory.length
  }
}];

// Prepare data for Account Switch Logger
const item = items[0].json;

return [{
  json: {
    ...item,
    service: 'gmail',
    fromAccount: item.accountUsed || 'unknown',
    toAccount: item.currentActive || 'unknown',
    reason: item.switchReason?.includes('limit') ? 'limit' : 
            item.switchReason?.includes('error') ? 'errors' : 'unknown',
    details: item.switchReason || ''
  }
}];

// Prepare data for Account Switch Logger
