// Categorize jobs: Portal Apply + Follow-up vs Cold Email vs Notification Only
// Now works with auto-extracted emails from job descriptions!
const jobs = items.map(item => {
  const job = item.json;
  const hasApplyUrl = !!(job['Apply URL'] || job.applyUrl);
  const hasRecruiterEmail = !!(job['Recruiter Email'] || job.recruiterEmail);
  const isNew = (job.Status || job.status || 'New').toLowerCase() === 'new';

  // Route logic:
  // Tier 1 (BEST): Has apply URL + has email → apply via portal + send follow-up
  // Tier 2 (GOOD): No apply URL + has email → cold email only  
  // Tier 3 (OK):   Has apply URL + no email → just notify to apply manually
  // Tier 4:        Neither → skip (waiting for you to find email)
  let applicationRoute;
  if (hasApplyUrl) {
    applicationRoute = 'direct_apply'; // Tier 1 or 3 (telegram + maybe email)
  } else if (hasRecruiterEmail) {
    applicationRoute = 'cold_email'; // Tier 2
  } else {
    applicationRoute = 'waiting'; // Nothing we can do yet
  }

  return {
    json: {
      ...job,
      hasApplyUrl,
      hasRecruiterEmail,
      isNew,
      applicationRoute
    }
  };
});

return jobs;

// Prepare direct-apply jobs list and route for follow-up emails
const directApplyJobs = items.filter(i => i.json.isNew && i.json.hasApplyUrl);

if (directApplyJobs.length === 0) {
  return [{ json: { message: 'No new direct-apply jobs today', count: 0, hasFollowUps: false } }];
}

const jobList = directApplyJobs.map((item, i) => {
  const j = item.json;
  const title = j['Job Title'] || j.jobTitle;
  const company = j.Company || j.company;
  const score = j.Score || j.score || '?';
  const url = j['Apply URL'] || j.applyUrl;
  const hasEmail = j.hasRecruiterEmail ? ' ✉️ (follow-up email will be sent)' : '';
  return `${i+1}. **${title}** at ${company} (Score: ${score})${hasEmail}\n   → ${url}`;
}).join('\n\n');

const withEmail = directApplyJobs.filter(i => i.json.hasRecruiterEmail).length;

const message = `🎯 **Apply Directly + Follow Up** (${directApplyJobs.length} jobs)

Apply through their portal FIRST, then we send follow-up emails to ${withEmail} recruiters saying you've applied:

${jobList}

💡 Strategy: Portal application + follow-up email = 3x response rate vs either alone.`;

return [{ json: { message, count: directApplyJobs.length, followUpCount: withEmail, hasFollowUps: withEmail > 0 } }];

// Get direct-apply jobs that also have recruiter emails
// These get a "I've applied, please consider" follow-up email
const config = $('User Config (Master Profile)').item.json;
const allJobs = $('Categorize: Apply Route').all();

const followUpJobs = allJobs.filter(item => 
  item.json.hasApplyUrl && item.json.hasRecruiterEmail && item.json.isNew
);

return followUpJobs.map(item => ({
  json: {
    ...item.json,
    emailType: 'follow_up_after_apply'
  }
}));

// Generate follow-up email: "I applied through your portal, please consider me"
const config = $('Merge User Config with Resume Data').item.json;
const job = items[0].json;

const prompt = `You are a professional email writer. Generate a SHORT follow-up email to a recruiter.

CONTEXT: The candidate has ALREADY APPLIED through the company's official application portal. This email is a polite follow-up to increase visibility.

**Job Details:**
- Title: ${job['Job Title'] || job.jobTitle}
- Company: ${job.Company || job.company}
- Recruiter: ${job['Recruiter Name'] || job.recruiterName || 'Hiring Manager'}
- Apply URL used: ${job['Apply URL'] || job.applyUrl}

**Candidate:**
- Name: ${config.name}
- Current Role: ${config.currentRole}
- Key Skills: ${(config.skills || []).slice(0, 5).join(', ')}
- Top Project: ${((config.resumeData || {}).projects || []).slice(0, 1).map(p => p.name + ' (' + (p.technologies || []).join(', ') + ')').join('')}

**Requirements:**
1. VERY SHORT (80-120 words max)
2. Open with: "I recently submitted my application for [role] through your portal"
3. Mention ONE specific skill/project that makes you a strong fit
4. Politely ask them to review your application
5. End with "Best regards, ${config.name}"
6. Tone: Professional, confident, not desperate

**Format:**
Subject: [Short subject - e.g., "Following up: Application for [Role]"]

[Short email body]

Provide ONLY the subject and body.`;

const response = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://api.groq.com/openai/v1/chat/completions',
  headers: {
    'Authorization': 'Bearer ' + (config.groqApiKey || ''),
    'Content-Type': 'application/json'
  },
  body: JSON.stringify({
    model: 'llama-3.3-70b-versatile',
    messages: [{ role: 'user', content: prompt }],
    temperature: 0.6
  }),
  json: true,
  timeout: 60000
});

const aiText = response.choices[0].message.content;

// Parse subject and body
let subject = 'Following up: Application for ' + (job['Job Title'] || job.jobTitle);
let body = aiText;

const subjectMatch = aiText.match(/Subject:\s*(.+?)\n/i);
if (subjectMatch) {
  subject = subjectMatch[1].trim();
  body = aiText.replace(/Subject:\s*.+?\n/i, '').trim();
}

// Add signature links
body += '\n\nLinkedIn: ' + (config.linkedinUrl || '');
body += '\nPortfolio: ' + (config.portfolioUrl || '');

return [{
  json: {
    ...job,
    emailSubject: subject,
    emailBody: body,
    emailType: 'follow_up'
  }
}];
